219→/// Scope-aware path hash that collapses repeated loop/call scopes.
220→///
221→/// Parses the flat trace into a tree of nested scopes, then for each scope_id
222→/// that appears multiple times at the same nesting level, collapses all
223→/// repetitions to a single sorted set of unique `(branch_id, taken)` pairs.
224→/// When `buckets` is non-empty, each distinct profile is also paired with
225→/// its iteration-count bucket so that different iteration counts produce
226→/// different hashes.
227→fn scope_aware_hash(events: &[crate::execution_record::TraceEvent], buckets: &LoopBuckets) -> u64 {
228→    use crate::execution_record::{ScopeEvent, TraceEvent};
229→    use std::collections::BTreeSet;
230→
231→    /// Discriminant tag for scope enter/exit matching.
232→    #[derive(Clone, Copy, PartialEq)]
233→    enum ScopeKind {
234→        Loop(u32),
235→        Call(u32),
236→    }
237→
238→    /// A sorted branch profile from one loop/call iteration.
239→    type BranchProfile = Vec<(u32, bool)>;
240→
241→    /// A profile paired with its optional iteration-count bucket.
242→    type ProfileWithBucket = (BranchProfile, Option<u32>);
243→
244→    /// Collapsed representation of a scope's content for hashing.
245→    #[derive(Hash)]
246→    enum CollapsedItem {
247→        /// A branch decision outside any scope at this level.
248→        Branch { branch_id: u32, taken: bool },
249→        /// A collapsed scope: set of distinct per-iteration branch profiles,
250→        /// each paired with its iteration-count bucket (or `None` when
251→        /// bucketing is disabled, preserving backward-compat hashing).
252→        Scope { scope_tag: u64, profile_buckets: Vec<ProfileWithBucket> },
253→    }
254→
255→    fn is_matching_exit(event: &TraceEvent, kind: ScopeKind) -> bool {
256→        match (kind, event) {
257→            (ScopeKind::Loop(id), TraceEvent::Scope { event: ScopeEvent::LoopExit { loop_id } }) => *loop_id == id,
258→            (ScopeKind::Call(id), TraceEvent::Scope { event: ScopeEvent::CallExit { call_site_id } }) => *call_site_id == id,
259→            _ => false,
260→        }
261→    }
262→
263→    /// Convert accumulated per-scope profile maps into `CollapsedItem::Scope`
264→    /// entries appended to `items`. Called at both the normal end of `collapse()`
265→    /// and the early return on parent-scope exit — without this, nested scopes
266→    /// would be invisible to their parent's branch profile.
267→    fn emit_scope_items(
268→        items: &mut Vec<CollapsedItem>,
269→        loop_profiles: &HashMap<u32, HashMap<BranchProfile, u32>>,
270→        call_profiles: &HashMap<u32, HashMap<BranchProfile, u32>>,
271→        buckets: &LoopBuckets,
272→    ) {
273→        let mut scope_ids: Vec<(u64, Vec<ProfileWithBucket>)> = Vec::new();
274→        for (id, profiles) in loop_profiles {
275→            let tag = (*id as u64) | (1u64 << 32);
276→            let mut sorted: Vec<ProfileWithBucket> = profiles
277→                .iter()
278→                .map(|(profile, &count)| {
279→                    let bucket = if buckets.is_disabled() { None } else { Some(buckets.bucket(count)) };
280→                    (profile.clone(), bucket)
281→                })
282→                .collect();
283→            sorted.sort();
284→            scope_ids.push((tag, sorted));
285→        }
286→        for (id, profiles) in call_profiles {
287→            let tag = (*id as u64) | (2u64 << 32);
288→            let mut sorted: Vec<ProfileWithBucket> = profiles
289→                .iter()
290→                .map(|(profile, &count)| {
291→                    let bucket = if buckets.is_disabled() { None } else { Some(buckets.bucket(count)) };
292→                    (profile.clone(), bucket)
293→                })
294→                .collect();
295→            sorted.sort();
296→            scope_ids.push((tag, sorted));
297→        }
298→        scope_ids.sort_by_key(|(tag, _)| *tag);
299→        for (scope_tag, profile_buckets) in scope_ids {
300→            items.push(CollapsedItem::Scope { scope_tag, profile_buckets });
301→        }
302→    }
303→
304→    fn collapse(events: &[TraceEvent], buckets: &LoopBuckets) -> (Vec<CollapsedItem>, usize) {
305→        let mut items: Vec<CollapsedItem> = Vec::new();
306→        let mut loop_profiles: HashMap<u32, HashMap<BranchProfile, u32>> = HashMap::new();
307→        let mut call_profiles: HashMap<u32, HashMap<BranchProfile, u32>> = HashMap::new();
308→
309→        let mut i = 0;
310→        while i < events.len() {
311→            match &events[i] {
312→                TraceEvent::Branch { decision } => {
313→                    items.push(CollapsedItem::Branch {
314→                        branch_id: decision.branch_id,
315→                        taken: decision.taken,
316→                    });
317→                    i += 1;
318→                }
319→                TraceEvent::Scope { event } => {
320→                    let (kind, is_enter) = match event {
321→                        ScopeEvent::LoopEnter { loop_id } => (ScopeKind::Loop(*loop_id), true),
322→                        ScopeEvent::LoopExit { loop_id } => (ScopeKind::Loop(*loop_id), false),
323→                        ScopeEvent::CallEnter { call_site_id } => (ScopeKind::Call(*call_site_id), true),
324→                        ScopeEvent::CallExit { call_site_id } => (ScopeKind::Call(*call_site_id), false),
325→                    };
326→
327→                    if !is_enter {
328→                        // Exit without matching enter — we've hit the boundary
329→                        // of our parent scope. Emit accumulated scope items
330→                        // before returning so nested scopes are visible to
331→                        // the parent's branch profile.
332→                        emit_scope_items(&mut items, &loop_profiles, &call_profiles, buckets);
333→                        return (items, i);
334→                    }
335→
336→                    // Recursively collapse the scope body
337→                    let body_start = i + 1;
338→                    let (child_items, consumed) = collapse(&events[body_start..], buckets);
339→                    let body_end = body_start + consumed;
340→
341→                    // Build this iteration's branch profile (sorted for determinism)
342→                    let mut profile = BTreeSet::new();
343→                    for item in &child_items {
344→                        match item {
345→                            CollapsedItem::Branch { branch_id, taken } => {
346→                                profile.insert((*branch_id, *taken));
347→                            }
348→                            CollapsedItem::Scope { scope_tag, profile_buckets } => {
349→                                let mut h = DefaultHasher::new();
350→                                scope_tag.hash(&mut h);
351→                                profile_buckets.hash(&mut h);
352→                                let synthetic_id = (h.finish() & 0x7FFF_FFFF) as u32 | 0x8000_0000;
353→                                profile.insert((synthetic_id, true));
354→                            }
355→                        }
356→                    }
357→                    let profile_vec: Vec<(u32, bool)> = profile.into_iter().collect();
358→
359→                    // Increment iteration count for this (scope_id, profile) pair
360→                    match kind {
361→                        ScopeKind::Loop(id) => {
362→                            *loop_profiles.entry(id).or_default().entry(profile_vec).or_insert(0) += 1;
363→                        }
364→                        ScopeKind::Call(id) => {
365→                            *call_profiles.entry(id).or_default().entry(profile_vec).or_insert(0) += 1;
366→                        }
367→                    }
368→
369→                    // Skip past the exit event if present
370→                    i = body_end;
371→                    if i < events.len() && is_matching_exit(&events[i], kind) {
372→                        i += 1;
373→                    }
374→                }
375→            }
376→        }
377→
378→        emit_scope_items(&mut items, &loop_profiles, &call_profiles, buckets);
379→        (items, events.len())
380→    }
381→
382→    let (items, _) = collapse(events, buckets);
383→    let mut hasher = DefaultHasher::new();
384→    for item in &items {
385→        item.hash(&mut hasher);
386→    }
387→    hasher.finish()
388→}
