390→/// Confidence-scored label for error intent classification.
391→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
392→pub struct ErrorIntentLabel {
393→    /// "likely_validation", "likely_runtime", or "unknown"
394→    pub label: String,
395→    /// Confidence score 0.0–1.0
396→    pub confidence: f64,
397→}
398→
399→/// Classify whether a thrown error is a deliberate validation rejection or an
400→/// accidental runtime failure by examining the branch path immediately before the error.
401→///
402→/// Pattern: a guard branch taken=true followed immediately by the error (no intervening
403→/// branches) suggests intentional input rejection. Errors without a preceding guard
404→/// or deep in the branch path are more likely accidental.
405→pub fn classify_error_intent(result: &crate::protocol::ExecuteResult) -> Option<ErrorIntentLabel> {
406→    let error = result.thrown_error.as_ref()?;
407→
408→    // If the frontend already classified this as infrastructure, trust it
409→    if error.error_category.as_deref() == Some("infrastructure") {
410→        return Some(ErrorIntentLabel {
411→            label: "likely_runtime".into(),
412→            confidence: 0.9,
413→        });
414→    }
415→
416→    let branch_path = &result.branch_path;
417→    if branch_path.is_empty() {
418→        // No branch data — can't infer intent
419→        return Some(ErrorIntentLabel {
420→            label: "unknown".into(),
421→            confidence: 0.0,
422→        });
423→    }
424→
425→    // Check the last branch before the error
426→    let last_branch = branch_path.last().unwrap();
427→
428→    // Guard pattern: last branch taken=true, suggesting an if-guard that led to a throw.
429→    // Shallow depth (few branches) + guard = likely validation.
430→    if last_branch.taken && branch_path.len() <= 3 {
431→        return Some(ErrorIntentLabel {
432→            label: "likely_validation".into(),
433→            confidence: 0.7,
434→        });
435→    }
436→
437→    // Deep branch path with error = likely accidental runtime failure
438→    if branch_path.len() > 5 {
439→        return Some(ErrorIntentLabel {
440→            label: "likely_runtime".into(),
441→            confidence: 0.6,
442→        });
443→    }
444→
445→    // Frontend-level classification can help disambiguate
446→    if error.error_category.as_deref() == Some("validation") {
447→        return Some(ErrorIntentLabel {
448→            label: "likely_validation".into(),
449→            confidence: 0.8,
450→        });
451→    }
452→    if error.error_category.as_deref() == Some("runtime") {
453→        return Some(ErrorIntentLabel {
454→            label: "likely_runtime".into(),
455→            confidence: 0.7,
456→        });
457→    }
458→
459→    Some(ErrorIntentLabel {
460→        label: "unknown".into(),
461→        confidence: 0.3,
462→    })
463→}
