470→/// Send a Setup command to the frontend and return a `SetupContextStack`
471→/// containing the returned context at the given level.
472→pub(crate) async fn send_setup(
473→    frontend: &mut Frontend,
474→    setup_file: &str,
475→    scope: &str,
476→    level: SetupLevel,
477→    project_root: Option<String>,
478→) -> Result<Option<SetupContextStack>, ExploreError> {
479→    let response = frontend
480→        .send(ProtoCommand::Setup {
481→            file: setup_file.to_string(),
482→            scope: scope.to_string(),
483→            level,
484→            project_root,
485→            parent_context: None,
486→        })
487→        .await?;
488→    match response.result {
489→        ResponseResult::Setup { setup_context } => Ok(Some(SetupContextStack {
490→            contexts: vec![SetupContextEntry {
491→                level,
492→                context: setup_context,
493→            }],
494→        })),
495→        ResponseResult::Error { message, .. } => {
496→            log::warn!("setup error for {scope}: {message}");
497→            Ok(None)
498→        }
499→        other => Err(ExploreError::UnexpectedResponse(format!(

500→            "expected Setup response, got {other:?}"
501→        ))),
502→    }
503→}
