505→/// Send a Teardown command to the frontend.
506→pub(crate) async fn send_teardown(frontend: &mut Frontend, scope: &str, level: SetupLevel) -> Result<(), ExploreError> {
507→    let response = frontend
508→        .send(ProtoCommand::Teardown {
509→            scope: scope.to_string(),
510→            level,
511→        })
512→        .await?;
513→    match response.result {
514→        ResponseResult::TeardownAck => Ok(()),
515→        ResponseResult::Error { message, .. } => {
516→            log::warn!("teardown error for {scope}: {message}");
517→            Ok(())
518→        }
519→        other => Err(ExploreError::UnexpectedResponse(format!(
520→            "expected TeardownAck response, got {other:?}"
521→        ))),
522→    }
523→}
