525→/// Explore a single function by generating random inputs and executing them.
526→///
527→/// When `setup_mgr` is provided, setup lifecycle is tracked through the
528→/// `SetupManager` (context caching, failure tracking, skip decisions).
529→/// When `None`, uses the legacy direct-send approach.
530→pub async fn explore_function(
531→    frontend: &mut Frontend,
532→    analysis: &FunctionAnalysis,
533→    config: &ExploreConfig,
534→    mut setup_mgr: Option<&mut SetupManager>,
535→) -> Result<ObservationOutput, ExploreError> {
536→    let instrument_response = frontend
537→        .send(ProtoCommand::Instrument {
538→            file: config.file.clone(),
539→            function: analysis.name.clone(),
540→            mocks: config.mocks.clone(),
541→            project_root: config.project_root.clone(),
542→        })
543→        .await?;
544→
545→    let instrumentable_line_count = match instrument_response.result {
546→        ResponseResult::Instrument { instrumented, instrumentable_line_count, .. } => {
547→            if !instrumented {
548→                return Err(ExploreError::UnexpectedResponse(
549→                    "instrumentation returned instrumented=false".to_string(),
550→                ));
551→            }
552→            instrumentable_line_count
553→        }
554→        ResponseResult::Error { code, message, .. } => {
555→            return Err(ExploreError::UnexpectedResponse(format!(
556→                "instrument error ({code:?}): {message}"
557→            )));
558→        }
559→        other => {
560→            return Err(ExploreError::UnexpectedResponse(format!(
561→                "expected Instrument response, got {other:?}"
562→            )));
563→        }
564→    };
565→
566→    let mut rng = match config.seed {
567→        Some(seed) => StdRng::seed_from_u64(seed),
568→        None => StdRng::from_os_rng(),
569→    };
570→
571→    // --- Setup lifecycle ---
572→    let has_setup =
573→        config.setup_file.is_some() && frontend_supports(&config.capabilities, "setup");
574→    let per_function_setup = has_setup && config.setup_level == SetupLevel::Function;
575→    let per_execution_setup = has_setup && config.setup_level == SetupLevel::Execution;
576→
577→    let mut setup_context: Option<SetupContextStack> = None;
578→
579→    // When a SetupManager is provided, check should_skip and cache contexts.
580→    let skip_setup = setup_mgr.as_ref().is_some_and(|m| m.should_skip(config.setup_level));
581→
582→    if per_function_setup && !skip_setup
583→        && let Some(ref setup_file) = config.setup_file
584→    {
585→        match send_setup(frontend, setup_file, &analysis.name, config.setup_level, config.project_root.clone()).await? {
586→            Some(ctx) => {
587→                if let Some(ref mut mgr) = setup_mgr
588→                    && let Some(entry) = ctx.contexts.first()
589→                {
590→                    let _ = mgr.setup(config.setup_level, &analysis.name, entry.context.clone());
591→                }
592→                setup_context = Some(ctx);
593→            }
594→            None => {
595→                if let Some(ref mut mgr) = setup_mgr {
596→                    let _ = mgr.record_failure(
597→                        config.setup_level,
598→                        format!("setup returned no context for {}", analysis.name),
599→                    );
600→                }
601→            }
602→        }
603→    }
604→
605→    // --- Generator prefetch ---
606→    let has_generators = config
607→        .value_sources
608→        .iter()
609→        .any(|s| matches!(s, ValueSource::CustomGenerator { .. }));
610→    let use_generators = has_generators && frontend_supports(&config.capabilities, "generate");
611→
612→    let mut prefetched = if use_generators {
613→        prefetch_custom_values(&config.value_sources, frontend, config.max_iterations as usize)
614→            .await
615→            .unwrap_or_else(|e| {
616→                log::debug!("prefetch failed, falling back to built-in: {e}");
617→                PrefetchedValues::new()
618→            })
619→    } else {
620→        PrefetchedValues::new()
621→    };
622→
623→    let mut seen_paths: HashSet<u64> = HashSet::new();
624→    let mut all_lines: HashSet<u32> = HashSet::new();
625→    let mut new_path_executions: Vec<ExecutionSummary> = Vec::new();
626→    let mut raw_results: Vec<(Vec<serde_json::Value>, ExecuteResult)> = Vec::new();
627→    let mut iterations: u32 = 0;
628→    let mut path_counts: HashMap<u64, u32> = HashMap::new();
629→    let mut seen_branch_ids: HashSet<u32> = HashSet::new();
630→    let mut discoveries: Vec<(u32, DiscoveryMethod)> = Vec::new();
631→
632→    // --- Float probe phase ---
633→    // Probes consume from the iteration budget, contributing to seen_paths and raw_results.
634→    let float_indices = crate::float_probe::float_param_indices(&analysis.params);
635→    let mut float_probe_results: Vec<crate::float_probe::FloatProbeResult> = Vec::new();
636→    let probe_budget = float_indices.len() * crate::float_probe::PROBE_COUNT * 2;
637→    if !float_indices.is_empty() && probe_budget < config.max_iterations as usize {
638→        for &idx in &float_indices {
639→            let pairs = crate::float_probe::generate_probe_pairs(
640→                &analysis.params,
641→                idx,
642→                crate::float_probe::PROBE_COUNT,
643→                &mut rng,
644→            );
645→            let mut agreements = 0usize;
646→            let mut total_probes = 0usize;
647→            let mut divergent_values = Vec::new();
648→
649→            for (float_inputs, floor_inputs) in pairs {
650→                let float_resp = frontend
651→                    .send(ProtoCommand::Execute {
652→                        function: analysis.name.clone(),
653→                        inputs: float_inputs.clone(),
654→                        mocks: config.mocks.clone(),
655→                        setup_context: setup_context.clone(),
656→                    })
657→                    .await?;
658→
659→                let floor_resp = frontend
660→                    .send(ProtoCommand::Execute {
661→                        function: analysis.name.clone(),
662→                        inputs: floor_inputs,
663→                        mocks: config.mocks.clone(),
664→                        setup_context: setup_context.clone(),
665→                    })
666→                    .await?;
667→
668→                if let (
669→                    ResponseResult::Execute(float_result),
670→                    ResponseResult::Execute(floor_result),
671→                ) = (&float_resp.result, &floor_resp.result) {
672→                    total_probes += 1;
673→
674→                    let fhash = path_hash(float_result, &config.loop_buckets);
675→                    let flhash = path_hash(floor_result, &config.loop_buckets);
676→                    seen_paths.insert(fhash);
677→                    seen_paths.insert(flhash);
678→                    for &line in &float_result.lines_executed {
679→                        all_lines.insert(line);
680→                    }
681→                    for &line in &floor_result.lines_executed {
682→                        all_lines.insert(line);
683→                    }
684→
685→                    if crate::float_probe::executions_agree(float_result, floor_result) {
686→                        agreements += 1;
687→                    } else if let Some(v) = float_inputs.get(idx).and_then(|v| v.as_f64()) {
688→                        divergent_values.push(v);
689→                    }
690→
691→                    raw_results.push((float_inputs.clone(), (**float_result).clone()));
692→                }
693→            }
694→
695→            let classification = crate::float_probe::classify(
696→                agreements,
697→                total_probes,
698→                crate::float_probe::AGREEMENT_THRESHOLD,
699→            );
700→            float_probe_results.push(crate::float_probe::FloatProbeResult {
701→                param_index: idx,
702→                param_name: analysis.params[idx].name.clone(),
703→                classification,
704→                agreements,
705→                total_probes,
706→                divergent_values,
707→            });
708→        }
709→    }
710→
711→    let float_bias = crate::float_probe::build_bias_map(&float_probe_results);
712→    let has_integer_treating = float_bias
713→        .values()
714→        .any(|c| *c == crate::float_probe::FloatClassification::IntegerTreating);
715→
716→    // --- User-provided candidate inputs (highest priority, no budget cap) ---
717→    let mut user_iter = config.user_seeds.iter().cloned().peekable();
718→
719→    // --- Literal-derived seed inputs ---
720→    // Execute extracted literals first to cover magic-value branches before random exploration.
721→    let literal_candidates = literals_to_candidate_inputs(&analysis.params, &analysis.literals);
722→    let literal_budget = literal_candidates
723→        .len()
724→        .min(config.max_iterations as usize / 2);
725→    let mut literal_iter = literal_candidates.into_iter().take(literal_budget).peekable();
726→
727→    // --- Candidate inputs (from --inputs or .shatter/ config) ---
728→    // Priority above pool seeds, below literal seeds.
729→    let candidate_budget = config
730→        .candidate_inputs
731→        .len()
732→        .min(config.max_iterations as usize / 3);
733→    let mut candidate_iter = config.candidate_inputs.iter().take(candidate_budget).cloned().peekable();
734→
735→    // --- Pool-derived seed inputs ---
736→    // Cross-function interesting values, injected after literals but before random generation.
737→    let pool_budget = config
738→        .pool_seeds
739→        .len()
740→        .min(config.max_iterations as usize / 4);
741→    let mut pool_iter = config.pool_seeds.iter().take(pool_budget).cloned().peekable();
742→
743→    let explore_start = Instant::now();
744→
745→    for _ in 0..config.max_iterations {
746→        if let Some(timeout) = config.timeout_explore
747→            && explore_start.elapsed() >= timeout
748→        {
749→            break;

750→        }
751→
752→        iterations += 1;
753→
754→        // --- Per-execution setup ---
755→        if per_execution_setup && !skip_setup
756→            && let Some(ref setup_file) = config.setup_file
757→        {
758→            match send_setup(frontend, setup_file, &analysis.name, config.setup_level, config.project_root.clone()).await? {
759→                Some(ctx) => {
760→                    if let Some(ref mut mgr) = setup_mgr
761→                        && let Some(entry) = ctx.contexts.first()
762→                    {
763→                        let _ = mgr.setup(config.setup_level, &analysis.name, entry.context.clone());
764→                    }
765→                    setup_context = Some(ctx);
766→                }
767→                None => {
768→                    if let Some(ref mut mgr) = setup_mgr {
769→                        let _ = mgr.record_failure(
770→                            config.setup_level,
771→                            format!("per-execution setup returned no context for {}", analysis.name),
772→                        );
773→                    }
774→                }
775→            }
776→        }
777→
778→        // --- Input generation ---
779→        // Priority: user seeds → literals → candidate inputs → pool seeds → custom generators → random.
780→        let inputs = if let Some(user_inputs) = user_iter.next() {
781→            user_inputs
782→        } else if let Some(lit_inputs) = literal_iter.next() {
783→            lit_inputs
784→        } else if let Some(cand_inputs) = candidate_iter.next() {
785→            cand_inputs
786→        } else if let Some(pool_inputs) = pool_iter.next() {
787→            pool_inputs
788→        } else if use_generators {
789→            generate_inputs_with_custom(
790→                &analysis.params,
791→                &config.value_sources,
792→                &mut prefetched,
793→                &mut rng,
794→                Some(&config.capabilities),
795→            )
796→        } else if has_integer_treating {
797→            crate::input_gen::generate_random_inputs_with_float_bias(
798→                &analysis.params,
799→                &float_bias,
800→                &mut rng,
801→                None,
802→            )
803→        } else {
804→            generate_random_inputs(&analysis.params, &mut rng, None)
805→        };
806→
807→        let response = frontend
808→            .send(ProtoCommand::Execute {
809→                function: analysis.name.clone(),
810→                inputs: inputs.clone(),
811→                mocks: config.mocks.clone(),
812→                setup_context: setup_context.clone(),
813→            })
814→            .await?;
815→
816→        let exec_result = match response.result {
817→            ResponseResult::Execute(result) => *result,
818→            ResponseResult::Error { code, message, .. } => {
819→                return Err(ExploreError::UnexpectedResponse(format!(
820→                    "execute error ({code:?}): {message}"
821→                )));
822→            }
823→            other => {
824→                return Err(ExploreError::UnexpectedResponse(format!("{other:?}")));
825→            }
826→        };
827→
828→        // --- Per-execution teardown ---
829→        if per_execution_setup && !skip_setup && frontend_supports(&config.capabilities, "teardown") {
830→            send_teardown(frontend, &analysis.name, config.setup_level).await?;
831→            if let Some(ref mut mgr) = setup_mgr {
832→                mgr.teardown(config.setup_level, &analysis.name);
833→            }
834→        }
835→
836→        for &line in &exec_result.lines_executed {
837→            all_lines.insert(line);
838→        }
839→
840→        let hash = path_hash(&exec_result, &config.loop_buckets);
841→        *path_counts.entry(hash).or_insert(0) += 1;
842→        let is_new = seen_paths.insert(hash);
843→
844→        // Track per-branch discovery attribution.
845→        for decision in &exec_result.branch_path {
846→            if seen_branch_ids.insert(decision.branch_id) {
847→                discoveries.push((decision.branch_id, DiscoveryMethod::Random));
848→            }
849→        }
850→
851→        if is_new {
852→            let error_intent = classify_error_intent(&exec_result);
853→            new_path_executions.push(ExecutionSummary {
854→                inputs: inputs.clone(),
855→                return_value: exec_result.return_value.clone(),
856→                thrown_error: exec_result
857→                    .thrown_error
858→                    .as_ref()
859→                    .map(|e| format!("{}: {}", e.error_type, e.message)),
860→                lines_executed: exec_result.lines_executed.clone(),
861→                is_new_path: true,
862→                error_intent,
863→            });
864→        }
865→
866→        raw_results.push((inputs, exec_result));
867→    }
868→
869→    // --- Per-function teardown ---
870→    if per_function_setup && !skip_setup && frontend_supports(&config.capabilities, "teardown") {
871→        send_teardown(frontend, &analysis.name, config.setup_level).await?;
872→        if let Some(ref mut mgr) = setup_mgr {
873→            mgr.teardown(config.setup_level, &analysis.name);
874→        }
875→    }
876→
877→    let total_lines = instrumentable_line_count
878→        .unwrap_or_else(|| analysis.end_line.saturating_sub(analysis.start_line) + 1);
879→
880→    Ok(ObservationOutput {
881→        function_name: analysis.name.clone(),
882→        iterations,
883→        unique_paths: seen_paths.len(),
884→        lines_covered: all_lines.len(),
885→        total_lines,
886→        new_path_executions,
887→        raw_results,
888→        discoveries,
889→        nondeterministic_fields: vec![],
890→        float_probe_results,
891→    })
892→}
