917→/// Render the bottom summary banner for an explore session.
918→pub fn format_explore_footer(
919→    total_paths: usize,
920→    function_count: usize,
921→    total_covered: usize,
922→    total_lines: u32,
923→    style: &crate::report_style::ReportStyle,
924→) -> String {
