12→use crate::types::{ParamInfo, TypeInfo};
13→
14→/// Maximum interpolation candidates generated per branch per exploration round.
15→pub const MAX_BOUNDARY_STEPS: usize = 4;
16→
17→/// Maximum branches to attempt boundary search per execution round.
18→pub const MAX_BOUNDARY_BRANCHES_PER_ROUND: usize = 3;
19→
20→/// Stop interpolating floats when the interval is narrower than this.
21→pub const FLOAT_CONVERGENCE_EPSILON: f64 = 1e-9;
22→
23→/// Find inputs that took opposite sides of a specific branch.
24→///
25→/// Scans `raw_results` for the most recent true-witness and false-witness
26→/// for `branch_id`. Returns `None` if both sides haven't been observed.
27→pub fn find_witness_pair(
28→    raw_results: &[(Vec<Value>, ExecuteResult)],
29→    branch_id: u32,
30→) -> Option<(Vec<Value>, Vec<Value>)> {
31→    let mut true_witness: Option<&Vec<Value>> = None;
32→    let mut false_witness: Option<&Vec<Value>> = None;
33→
34→    // Iterate in reverse to prefer recent witnesses (more likely near the boundary).
35→    for (inputs, result) in raw_results.iter().rev() {
36→        for decision in &result.branch_path {
37→            if decision.branch_id == branch_id {
38→                if decision.taken && true_witness.is_none() {
39→                    true_witness = Some(inputs);
40→                } else if !decision.taken && false_witness.is_none() {
41→                    false_witness = Some(inputs);
42→                }
43→                break;
44→            }
45→        }
46→        if true_witness.is_some() && false_witness.is_some() {
47→            break;
48→        }
49→    }
50→
51→    match (true_witness, false_witness) {
52→        (Some(tw), Some(fw)) => Some((tw.clone(), fw.clone())),
53→        _ => None,
54→    }
